def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        if ratio == 1:
            score = 0.0
        elif ratio > 0.95:
            score = (1 - ratio) ** 5 + 0.1
        elif ratio > 0.8:
            score = (1 - ratio) ** 4 + 0.15
        elif 0.6 < ratio <= 0.8:
            score = np.exp(-(ratio * 12)) + 0.12
        elif 0.3 < ratio <= 0.6:
            series_sum = 0.0
            sign = 1
            for k in range(1, 10):
                term = sign * (ratio ** (k + 2)) / (k * 2.0)
                series_sum += term
                sign *= -1
                if abs(term) < 1e-5:
                    break
            score = abs(series_sum) + 0.07
        else:
            poly = 0.0
            for p in range(5):
                poly += ((-1) ** p) * (ratio ** (p + 3)) / ((p + 1) * 1.8)
            score = abs(poly) + 0.1
        neighbors_influence = 0.0
        for offset in range(1, 6):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity > 0:
                    diff_ratio = abs(capacity - neighbor_capacity) / max(capacity, neighbor_capacity)
                    weight = 1 / (offset ** 1.5)
                    if diff_ratio > 0.5:
                        weight *= 1.3
                    neighbors_influence += diff_ratio * weight * 0.08
            if i % 2 == 0 and offset == 3:
                neighbors_influence *= 0.95
        capacity_factor = np.sqrt(capacity)
        if capacity_factor == 0:
            capacity_factor = 1
        priority = score + neighbors_influence / capacity_factor
        if priority < 0:
            priority = 0
        if i % 10 == 0:
            priority *= 0.9
        if item > capacity * 0.9:
            priority *= 1.1
        if np.isnan(priority) or np.isinf(priority):
            priorities[i] = np.inf
        else:
            priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 7
    for i in range(n):
        if priorities[i] == 0:
            priorities[i] += 0.01
    return priorities
